using System.Collections.Concurrent;
using sv_7205735d765f4dd0800338b85d75ad16.Models;

namespace sv_7205735d765f4dd0800338b85d75ad16.Services;

/// <summary>
/// Singleton service that stores wizard data keyed by session ID.
/// Accessible from both static SSR (layout) and interactive server (pages)
/// because it lives outside the per-request/per-circuit DI scope.
/// </summary>
public class ApplicationStateService
{
    private readonly ConcurrentDictionary<string, ApplicationData> _store = new();

    public ApplicationData GetOrCreate(string sessionId)
    {
        return _store.GetOrAdd(sessionId, _ => new ApplicationData());
    }

    public void Save(string sessionId, ApplicationData data)
    {
        _store[sessionId] = data;
    }

    public void Remove(string sessionId)
    {
        _store.TryRemove(sessionId, out _);
    }
}

