@inherits LayoutComponentBase
@inject sv_7205735d765f4dd0800338b85d75ad16.Services.ApplicationStateService StateService
@inject IHttpContextAccessor HttpContextAccessor

@{
    var path = HttpContextAccessor.HttpContext?.Request.Path.Value ?? "";
    var currentStep = path switch
    {
        "/apply/personal-info" => 1,
        "/apply/experience" => 2,
        "/apply/references" => 3,
        "/apply/review" => 4,
        _ => 0
    };

    var sessionId = HttpContextAccessor.HttpContext?.Request.Cookies["WizardSessionId"] ?? "";
    var completedSteps = new HashSet<int>();
    if (!string.IsNullOrEmpty(sessionId))
    {
        completedSteps = StateService.GetOrCreate(sessionId).CompletedSteps;
    }
}

<div class="page">
    <div class="sidebar">
        <NavMenu />
    </div>

    <main>
        <div class="top-row px-4">
            <div class="wizard-progress d-flex align-items-center w-100">
                <strong class="me-3">Step @currentStep of 4</strong>
                @for (int i = 1; i <= 4; i++)
                {
                    var step = i;
                    var label = step switch
                    {
                        1 => "Personal Info",
                        2 => "Experience",
                        3 => "References",
                        4 => "Review",
                        _ => ""
                    };
                    var href = step switch
                    {
                        1 => "/apply/personal-info",
                        2 => "/apply/experience",
                        3 => "/apply/references",
                        4 => "/apply/review",
                        _ => ""
                    };
                    var isActive = step == currentStep;
                    var isCompleted = completedSteps.Contains(step);
                    var badgeClass = isActive ? "bg-primary" : isCompleted ? "bg-success" : "bg-secondary";

                    <a href="@href" class="wizard-step text-decoration-none mx-1">
                        <span class="badge @badgeClass">@step. @label</span>
                    </a>
                }
            </div>
        </div>

        <article class="content px-4">
            @Body
        </article>
    </main>
</div>

<div id="blazor-error-ui" data-nosnippet>
    An unhandled error has occurred.
    <a href="." class="reload">Reload</a>
    <span class="dismiss">🗙</span>
</div>

.page {
    position: relative;
    display: flex;
    flex-direction: column;
}

main {
    flex: 1;
}

.sidebar {
    background-image: linear-gradient(180deg, rgb(5, 39, 103) 0%, #3a0647 70%);
}

.top-row {
    background-color: #f7f7f7;
    border-bottom: 1px solid #d6d5d5;
    height: 3.5rem;
    display: flex;
    align-items: center;
}

.wizard-step .badge {
    font-size: 0.85rem;
    padding: 0.4em 0.7em;
}

@media (min-width: 641px) {
    .page {
        flex-direction: row;
    }

    .sidebar {
        width: 250px;
        height: 100vh;
        position: sticky;
        top: 0;
    }

    .top-row {
        position: sticky;
        top: 0;
        z-index: 1;
    }

    .top-row, article {
        padding-left: 2rem !important;
        padding-right: 1.5rem !important;
    }
}

#blazor-error-ui {
    color-scheme: light only;
    background: lightyellow;
    bottom: 0;
    box-shadow: 0 -1px 2px rgba(0, 0, 0, 0.2);
    box-sizing: border-box;
    display: none;
    left: 0;
    padding: 0.6rem 1.25rem 0.7rem 1.25rem;
    position: fixed;
    width: 100%;
    z-index: 1000;
}

    #blazor-error-ui .dismiss {
        cursor: pointer;
        position: absolute;
        right: 0.75rem;
        top: 0.5rem;
    }

