@layout WizardLayout
@rendermode InteractiveServer
@inject sv_7205735d765f4dd0800338b85d75ad16.Services.ApplicationStateService StateService
@inject IHttpContextAccessor HttpContextAccessor
@inject NavigationManager Navigation

<PageTitle>Review — Apply</PageTitle>

<h1>Step 4: Review Your Application</h1>

@if (Data is not null)
{
    <h3>Personal Information</h3>
    <dl class="row" style="max-width: 600px;">
        <dt class="col-sm-3">Name</dt>
        <dd class="col-sm-9">@Data.Name</dd>
        <dt class="col-sm-3">Email</dt>
        <dd class="col-sm-9">@Data.Email</dd>
    </dl>

    <h3>Work Experience</h3>
    @if (Data.JobHistory.Count == 0)
    {
        <p class="text-muted">No jobs entered.</p>
    }
    else
    {
        <table class="table table-sm" style="max-width: 600px;">
            <thead><tr><th>Company</th><th>Title</th><th>Years</th></tr></thead>
            <tbody>
                @foreach (var job in Data.JobHistory)
                {
                    <tr><td>@job.Company</td><td>@job.Title</td><td>@job.Years</td></tr>
                }
            </tbody>
        </table>
    }

    <h3>References</h3>
    @if (Data.References.Count == 0)
    {
        <p class="text-muted">No references entered.</p>
    }
    else
    {
        <table class="table table-sm" style="max-width: 600px;">
            <thead><tr><th>Name</th><th>Email</th><th>Relationship</th></tr></thead>
            <tbody>
                @foreach (var r in Data.References)
                {
                    <tr><td>@r.Name</td><td>@r.Email</td><td>@r.Relationship</td></tr>
                }
            </tbody>
        </table>
    }

    <div class="mt-3">
        <a href="/apply/references" class="btn btn-secondary me-2">← Back</a>
        <button class="btn btn-success" @onclick="Submit">Submit Application</button>
    </div>

    @if (_submitted)
    {
        <div class="alert alert-success mt-3">Application submitted successfully!</div>
    }
}
else
{
    <p>No application data found. <a href="/apply/personal-info">Start over</a>.</p>
}

