@page "/apply/personal-info"
@layout WizardLayout
@rendermode InteractiveServer
@inject sv_7205735d765f4dd0800338b85d75ad16.Services.ApplicationStateService StateService
@inject IHttpContextAccessor HttpContextAccessor
@inject NavigationManager Navigation

<PageTitle>Personal Info — Apply</PageTitle>

<h1>Step 1: Personal Information</h1>

<div class="mb-3" style="max-width: 500px;">
    <label class="form-label">Full Name</label>
    <input class="form-control" @bind="Name" />
</div>
<div class="mb-3" style="max-width: 500px;">
    <label class="form-label">Email Address</label>
    <input class="form-control" type="email" @bind="Email" />
</div>

<button class="btn btn-primary" @onclick="Next">Next →</button>

@code {
    private string Name = string.Empty;
    private string Email = string.Empty;
    private string _sessionId = string.Empty;

    protected override void OnInitialized()
    {
        _sessionId = GetOrCreateSessionId();
        var data = StateService.GetOrCreate(_sessionId);
        Name = data.Name;
        Email = data.Email;
    }

    private void Next()
    {
        var data = StateService.GetOrCreate(_sessionId);
        data.Name = Name;
        data.Email = Email;
        data.CompletedSteps.Add(1);
        StateService.Save(_sessionId, data);
        Navigation.NavigateTo("/apply/experience", forceLoad: true);
    }

    private string GetOrCreateSessionId()
    {
        var httpContext = HttpContextAccessor.HttpContext;
        var sessionId = httpContext?.Request.Cookies["WizardSessionId"];
        if (string.IsNullOrEmpty(sessionId))
        {
            sessionId = Guid.NewGuid().ToString();
            httpContext?.Response.Cookies.Append("WizardSessionId", sessionId, new CookieOptions
            {
                HttpOnly = true,
                SameSite = SameSiteMode.Strict,
                MaxAge = TimeSpan.FromHours(4)
            });
        }
        return sessionId;
    }
}

