{
    if (context.Request.Path.StartsWithSegments("/apply")
        && !context.Request.Cookies.ContainsKey("WizardSessionId"))
    {
        context.Response.Cookies.Append("WizardSessionId", Guid.NewGuid().ToString(), new CookieOptions
        {
            HttpOnly = true,
            SameSite = SameSiteMode.Strict,
            MaxAge = TimeSpan.FromHours(4)
        });
    }
    await next();
});

